        }
      };
    default:
      throw Exception('unexpected AppRole: $role');
  }
}

DomainAccessibleContents _createDomainAccessibleContents(
    RoleLevel? level, bool isTeamCrossing) {
  final allow =
      ShortRoleInfo(isAccessible: true, isTeamCrossing: isTeamCrossing);
  const deny = ShortRoleInfo(isAccessible: false, isTeamCrossing: false);

  switch (level) {
    case RoleLevel.admin:
      return {
        RoleLevel.read: allow,
        RoleLevel.write: allow,
        RoleLevel.admin: allow,
      };
    case RoleLevel.write:
      return {
        RoleLevel.read: allow,
        RoleLevel.write: allow,
        RoleLevel.admin: deny,
      };
    case RoleLevel.read:
      return {
        RoleLevel.read: allow,
        RoleLevel.write: deny,
        RoleLevel.admin: deny,
      };
    default:
      return {
        RoleLevel.read: deny,
        RoleLevel.write: deny,
        RoleLevel.admin: deny,
      };
  }
}

void _mergeTeamAccessibleContents(
    TeamAccessibleContents dst, TeamAccessibleContents src) {
  for (final domain in RoleDomain.values) {
    final dstDomain = dst[domain]!;
    final srcDomain = src[domain]!;
    for (final level in [RoleLevel.read, RoleLevel.write, RoleLevel.admin]) {
      final dstLevel = dstDomain[level]!;
      final srcLevel = srcDomain[level]!;
      dstDomain[level] = ShortRoleInfo(
        isAccessible: dstLevel.isAccessible | srcLevel.isAccessible,
        isTeamCrossing: dstLevel.isTeamCrossing | srcLevel.isTeamCrossing,
      );
    }
  }
}

void _mergeUserAccessibleContents(
    UserAccessibleContents dst, UserAccessibleContents src) {
  for (final teamId in src.keys) {
    dst[teamId] ??= {
      for (final domain in RoleDomain.values)
        domain: _createDomainAccessibleContents(null, false),
    };
    _mergeTeamAccessibleContents(dst[teamId]!, src[teamId]!);
  }
  if (dst.containsKey(allTeams)) {
    for (final teamId in dst.keys.where((key) => key != allTeams)) {
      _mergeTeamAccessibleContents(dst[teamId]!, dst[allTeams]!);
    }
  }
}

UserAccessibleContents createAccessibleContents(
    Map<String, List<AppRole>> roles) {
  UserAccessibleContents result = {};
  for (final entry in roles.entries) {
    final teamId = entry.key;
    final appRoles = entry.value;
    for (final appRole in appRoles) {
      _mergeUserAccessibleContents(
        result,
        _createTeamAccessibleContents(teamId, appRole),
      );
    }
  }
  return result;
}

