/// {@category Data}
library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/data/models/enums/app_role.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/profile.dart';
import 'package:baseball_detector_flutter/data/models/short_role_info.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/models/user_role.dart';

part 'user_info.freezed.dart';
part 'user_info.g.dart';

// This typedef must be in this file because json_serializable crashes
typedef DomainAccessibleContents = Map<RoleLevel, ShortRoleInfo>;
typedef TeamAccessibleContents = Map<RoleDomain, DomainAccessibleContents>;
typedef UserAccessibleContents = Map<String, TeamAccessibleContents>;

const allTeams = 'all';

// dummy class for generating TeamAccessibleContents serializer
@JsonSerializable(explicitToJson: true)
class _UserAccessContents {
  final UserAccessibleContents data;

  const _UserAccessContents(this.data);
}

class UserAccessContentsConverter {
  UserAccessContentsConverter._();

  static UserAccessibleContents fromJson(Map<String, dynamic> json) =>
      _$UserAccessContentsFromJson({'data': json}).data;
}

extension UserAccessibleContentsExt on UserAccessibleContents {
  bool hasPrivilegesFor(
    String teamId,
    RoleDomain domain,
    RoleLevel level,
    bool shouldCheckTeamCrossing,
  ) {
    final shortRoleInfo = (this[teamId] ?? this[allTeams])?[domain]?[level];
    if (shortRoleInfo == null) {
      return false;
    }

    return shouldCheckTeamCrossing
        ? shortRoleInfo.isAccessible && shortRoleInfo.isTeamCrossing
        : shortRoleInfo.isAccessible;
  }

  Map<String, dynamic> toJson() =>
      _$UserAccessContentsToJson(_UserAccessContents(this))['data'];
}

@freezed
abstract class UserInfo with _$UserInfo {
  const UserInfo._();

  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  const factory UserInfo({
    required String id,
    String? email,
    DateTime? deletedAt, // assumes UTC
    DateTime? createdAt, // assumes UTC
    DateTime? updatedAt, // assumes UTC
    required Profile profile,
    required UserAccessibleContents accessibleContents,
    required Map<String, List<UserRole>> givenUserRoles,
    required List<Team> teams,
  }) = _UserInfo;

  factory UserInfo.fromJson(Map<String, dynamic> json) =>
      _$UserInfoFromJson(json);

  bool isDeactivated(String? teamId) {
    if (teamId == null) return true;
    final roles = givenUserRoles[teamId];
    if (roles == null || roles.isEmpty) return true;
    // Check if the user has any active role in the team
    return roles.first.deleteFlag;
  }

  AppRole? getAppRoleFor(String teamId) {
    // First check for direct team assignment
    final directRole = givenUserRoles[teamId]?.firstOrNull?.roleGroup.name;
    if (directRole != null) {
      return directRole;
    }

    // For super_admin users, check if they have super_admin role for any team
    // If so, they should have super_admin privileges for all teams

